onClick:
{{
(() => {
  // ✅ CAPTURA INMEDIATA
  const fechaFinManual = date_two.selectedDate;
  const fechaInicioManual = date_one.selectedDate;

  // Guardar inmediatamente en el store para que el Default Date lo reconozca al refrescar
  storeValue("fecha_fin_temp", fechaFinManual || null, false);

  const trim = (v) => String(v ?? "").trim();
  const has = (v) => trim(v).length > 0;

  // 1) Validaciones
  if (!select_one?.selectedOptionValue) {
    showAlert("Selecciona la ubicación.", "warning");
    return;
  }
  if (!select_four?.selectedOptionValue) {
    showAlert("Selecciona el baño.", "warning");
    return;
  }
  if (!has(fechaInicioManual)) {
    showAlert("Selecciona la fecha de inicio.", "warning");
    return;
  }

  const rawBase = input_four?.text ?? "";
  const cleanBase = String(rawBase).replace(/,/g, "").trim();

  // 2) Validación de fechas
  const ini = new Date(fechaInicioManual);
  const fin = new Date(fechaFinManual);
  if (!isNaN(ini.getTime()) && !isNaN(fin.getTime()) && fin < ini) {
    showAlert("La fecha de recolección no puede ser anterior a la de inicio.", "warning");
    return;
  }

  // 3) Cambio de baño
  const idBanoOriginal = appsmith.store.bano_original_pedido || null;
  const idBanoNuevo = select_four?.selectedOptionValue ? String(select_four.selectedOptionValue).trim() : null;
  const huboCambio = idBanoOriginal && idBanoNuevo ? idBanoNuevo !== idBanoOriginal : false;

  // 4) Guardar resto de info
  storeValue("pedido_edit_temp", {
    fecha_inicio: fechaInicioManual || null,
    fecha_fin: fechaFinManual || null,
    precio_sin_iva: cleanBase || null
  }, false);

  storeValue("bano_nuevo_seleccionado", idBanoNuevo, true);
  storeValue("cambio_bano", huboCambio, true);

  const msgCambio = huboCambio
    ? `Se cambiará el baño: ${idBanoOriginal} → ${idBanoNuevo}`
    : `No hay cambio de baño.`;
  storeValue("mensaje_cambio_bano", msgCambio, true);

  showModal("Modal_confirmar_editar");
})()
}}
